// Get user message from webhook
const item = $input.first().json;
const userMessage = item.body?.chatInput || item.body?.message || '';
const sessionId = item.headers?.['x-session-id'] || `SESS_${Date.now()}_${Math.random().toString(36).substring(2, 10)}`;

return [{
  json: {
    userMessage: userMessage,
    sessionId: sessionId,
    timestamp: new Date().toISOString(),
    negotiationCount: 0
  }
}];

const aiResponse = $input.first().json.message?.content || '';

let intent = 'general';
let status = 'pending';
let product = '';
let quantity = '';
let customerName = '';
let phone = '';
let address = '';
let orderData = {};
let cleanedReply = aiResponse;

// Check for ORDER_CONFIRMED
if (aiResponse.includes('ORDER_CONFIRMED')) {
  intent = 'order';
  status = 'confirmed';

  const productMatch = aiResponse.match(/Product:([^|]+)/);
  const quantityMatch = aiResponse.match(/Quantity:([^|]+)/);
  const nameMatch = aiResponse.match(/Name:([^|]+)/);
  const phoneMatch = aiResponse.match(/Phone:([^|]+)/);
  const addressMatch = aiResponse.match(/Address:([^|]+)/);

  product = productMatch ? productMatch[1].trim() : '';
  quantity = quantityMatch ? quantityMatch[1].trim() : '';
  customerName = nameMatch ? nameMatch[1].trim() : '';
  phone = phoneMatch ? phoneMatch[1].trim() : '';
  address = addressMatch ? addressMatch[1].trim() : '';

  orderData = { product, quantity, customerName, phone, address };
  cleanedReply = aiResponse.replace(/ORDER_CONFIRMED\|.*/, '').trim();
}
// Check for CANCELLED
else if (aiResponse.includes('CANCELLED')) {
  intent = 'cancel';
  status = 'cancelled';
  const reasonMatch = aiResponse.match(/Reason:([^|]+)/);
  orderData = { reason: reasonMatch ? reasonMatch[1].trim() : 'User cancelled' };
  cleanedReply = aiResponse.replace(/CANCELLED\|.*/, '').trim();
}
// Check for NEGOTIATION
else if (aiResponse.includes('NEGOTIATION')) {
  intent = 'negotiation';
  status = 'negotiating';
  cleanedReply = aiResponse.replace(/NEGOTIATION\|.*/, '').trim();
}
// Check for booking
else if (aiResponse.toLowerCase().includes('book') || aiResponse.toLowerCase().includes('appointment')) {
  intent = 'booking';
}

// Clean the response
cleanedReply = cleanedReply.replace(/[*_#`]/g, '').replace(/\s+/g, ' ').trim();

return [{
  json: {
    ...$input.first().json,
    aiReply: aiResponse,
    cleanedReply: cleanedReply || aiResponse,
    intent: intent,
    status: status,
    product: product,
    quantity: quantity,
    customerName: customerName,
    phone: phone,
    address: address,
    orderData: JSON.stringify(orderData)
  }
}];

const response = {
  reply: $json.cleanedReply || $json.aiReply || 'Processing complete',
  intent: $json.intent || 'general',
  status: $json.status || 'completed',
  sessionId: $json.sessionId
};

return [{ json: response }];
